#include <stdio.h>

// 8:1 Multiplexer function
int mux_8to1(int* inputs, int select, int enable) {
    // If enable is LOW, output is disabled (0)
    if (enable == 0) {
        return 0;
    }

    // Validate select lines (0-7 for 8 inputs)
    if (select < 0 || select > 7) {
        return -1; // Error
    }

    // Return the selected input
    return inputs[select];
}

int main() {
    // 8 data inputs: I0, I1, I2, I3, I4, I5, I6, I7
    int inputs[8] = {0, 1, 0, 1, 1, 0, 1, 0};
    int select = 5;  // Binary 101 selects I5
    int enable = 1;  // MUX enabled

    int output = mux_8to1(inputs, select, enable);
    printf("8:1 MUX Output: %d\n", output);  // Output: 0

    return 0;
}

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity mux_4to1 is
    Port ( I : in STD_LOGIC_VECTOR (3 downto 0);  -- 4 data inputs
           S : in STD_LOGIC_VECTOR (1 downto 0);  -- 2 select lines
           Y : out STD_LOGIC);                     -- Output
end mux_4to1;

architecture Behavioral of mux_4to1 is
begin
    -- Process with case statement for selection
    process(I, S)
    begin
        case S is
            when "00" => Y <= I(0);  -- Select I0
            when "01" => Y <= I(1);  -- Select I1
            when "10" => Y <= I(2);  -- Select I2
            when "11" => Y <= I(3);  -- Select I3
            when others => Y <= '0';
        end case;
    end process;
end Behavioral;
